# A mini capstone: Student grade tracker
class Student:
    def __init__(self, name):
        self.name = name
        self.grades = []

    def add_grade(self, grade):
        if not 0 <= grade <= 100:
            raise ValueError(f"Grade must be 0-100, got {grade}")
        self.grades.append(grade)

    def average(self):
        if not self.grades:
            return 0
        return sum(self.grades) / len(self.grades)

    def letter_grade(self):
        avg = self.average()
        if avg >= 90: return 'A'
        elif avg >= 80: return 'B'
        elif avg >= 70: return 'C'
        else: return 'F'

    def __str__(self):
        return f"{self.name}: avg={self.average():.1f} ({self.letter_grade()})"

alice = Student("Alice")
for g in [92, 88, 95, 79]:
    alice.add_grade(g)
print(alice)

