class Student:
    def __init__(self, name):
        self.name = name
        self.grades = []

    def add_grade(self, grade):
        self.grades.append(grade)

    def average(self):
        if not self.grades:
            return 0
        return sum(self.grades) / len(self.grades)

    def __str__(self):
        return f"{self.name}: avg {self.average():.1f}"

student = Student("Alice")
for g in [85, 92, 78, 96]:
    student.add_grade(g)
print(student)
